import math
import random
import statistics

def derive_parameter(inputs):
    # Normalize inputs to a dict name->value (floats)
    params = {}
    if isinstance(inputs, dict):
        for k, v in inputs.items():
            val = None
            if isinstance(v, dict):
                val = v.get('value', None)
            else:
                val = v
            if val is None:
                continue
            try:
                params[k] = float(val)
            except (TypeError, ValueError):
                pass
    else:
        try:
            params = {x['name']: float(x['value']) for x in inputs}
        except Exception:
            params = {}
            for x in inputs:
                if isinstance(x, dict) and 'name' in x and 'value' in x:
                    try:
                        params[x['name']] = float(x['value'])
                    except Exception:
                        pass

    seed = int(params.get('random_seed', 12345))
    random.seed(seed)

    # Empirical reported terminal maturation durations (hours)
    reported_hours = [
        float(params['t_activation_fastdc_hours']),
        float(params['t_terminal_maturation_hours_24']),
        float(params['t_terminal_maturation_hours_48'])
    ]
    hours_per_day = float(params['hours_per_day'])
    sd_h = float(params['time_measurement_sd_hours'])
    p_min = float(params['completion_fraction_min'])
    p_max = float(params['completion_fraction_max'])
    n_boot = int(params['n_boot'])

    draws = []
    for _ in range(n_boot):
        # Bootstrap resample: pick one reported duration with replacement
        t_h = random.choice(reported_hours)
        # Add measurement/protocol noise (Gaussian), truncated at > 1 hour
        t_h_noisy = max(1.0, random.gauss(t_h, sd_h))
        # Convert to days
        t_days = t_h_noisy / hours_per_day
        # Sample completion fraction considered as 'complete' in the report
        p = random.uniform(p_min, p_max)
        # First-order maturation: time to reach fraction p is t = -ln(1-p)/k -> k = -ln(1-p)/t
        k = -math.log(1.0 - p) / t_days
        draws.append(k)

    # Robust summary statistics
    draws_sorted = sorted(draws)
    n = len(draws_sorted)
    def pct(q):
        idx = q*(n-1)
        lo = int(math.floor(idx))
        hi = int(math.ceil(idx))
        w = idx - lo
        return (1-w)*draws_sorted[lo] + w*draws_sorted[hi]

    median_param = pct(0.5)
    q1 = pct(0.25)
    q3 = pct(0.75)
    iqr_param = q3 - q1
    ci95_param = [pct(0.025), pct(0.975)]

    return {
        'median_param': median_param,
        'iqr_param': iqr_param,
        'ci95_param': ci95_param
    }
